def bootstrap(rows,decisions):
 """5000-кратный cluster bootstrap; единица выборки — prospective run_id."""
 labels=rows.episode_class.astype(str).reset_index(drop=True);run_values=[]
 for _,idx in rows.groupby("run_id",sort=False).groups.items():
  idx=list(idx);r=rows.loc[idx].reset_index(drop=True);d=decisions.loc[idx].reset_index(drop=True);metrics=subset(r,d)
  attack=r.episode_class.ne("benign").to_numpy();strong=d.strong_attack_evidence.to_numpy(bool)
  correct=np.array([flag and top==truth for flag,top,truth in zip(strong,d.top_class.astype(str),r.episode_class.astype(str))])
  conformal_cover=np.array([truth in values for truth,values in zip(r.episode_class.astype(str),d.conformal_set)])
  support_top2=np.array([ranks[truth]<=2 for truth,ranks in zip(r.episode_class.astype(str),d.support_ranks)])
  run_values.append({
   "closed_set_macro_f1":metrics["closed_set_macro_f1"],"closed_set_benign_recall":metrics["closed_set_benign_recall"],"closed_set_FPR":metrics["closed_set_FPR"],
   "strong_evidence_precision":float(correct.sum()/max(strong.sum(),1)),"strong_evidence_recall":float(correct[attack].mean()),
   "true_class_evidence_window_recall":metrics["true_class_evidence_window_recall"],"benign_window_recall":metrics["benign_recall"],"benign_window_FPR":metrics["false_positive_rate"],
   "review_rate":metrics["review_rate"],"attack_review_rate":metrics["attack_review_rate"],"attack_episode_recall":metrics["attack_episode_recall"],
   "benign_episode_false_alert_rate":metrics["benign_episode_false_alert_rate"],"episode_alert_precision":metrics["episode_alert_precision"],
   "detection_by_second_window":metrics["detection_by_second_window"],"median_time_to_alert":float(metrics["time_to_first_alert"]["median"] or 0),
   "conformal_coverage":float(conformal_cover.mean()),"support_top2_rate":float(support_top2.mean())})
 names=list(run_values[0]);matrix=np.array([[value[name] for name in names] for value in run_values],dtype=float);rng=np.random.default_rng(42)
 samples=matrix[rng.integers(0,len(matrix),size=(5000,len(matrix)))].mean(axis=1)
